import crash_landing_story from '../../../../../坠星大陆/角色卡/世界书/迫降线.txt?raw';

export const CRASH_LANDING_STORY_MARKER = '坠星盆地的湖水';

/** 聊天记录中是否已有迫降线剧情（含写在 0 楼或其它楼层） */
export function has_crash_landing_story(): boolean {
  if (typeof getChatMessages !== 'function') {
    return false;
  }
  return getChatMessages('0-{{lastMessageId}}').some(msg => msg.message.includes(CRASH_LANDING_STORY_MARKER));
}

/** 迫降线是否已写在第 0 楼 */
export function has_crash_landing_on_floor_zero(): boolean {
  if (typeof getChatMessages !== 'function') {
    return false;
  }
  const msg = getChatMessages(0)[0];
  return !!msg?.message?.includes(CRASH_LANDING_STORY_MARKER);
}

/**
 * 将迫降线开场剧情写入第 0 楼（打包自角色卡文本），不新建楼层、不触发生成。
 * 正文保留 `<story>` 与 `<StatusPlaceHolderImpl/>`，供酒馆正则渲染。
 */
export async function push_crash_landing_story(): Promise<void> {
  if (has_crash_landing_on_floor_zero()) {
    console.info('[迫降线] 第 0 楼已有剧情，跳过写入');
    return;
  }

  if (has_crash_landing_story()) {
    console.info('[迫降线] 剧情已存在于其它楼层，跳过写入');
    return;
  }

  const story = crash_landing_story.trim();
  if (!story) {
    throw new Error('迫降线剧情文本为空');
  }

  const floor_zero = getChatMessages(0)[0];
  if (!floor_zero) {
    throw new Error('第 0 楼不存在，无法写入迫降线剧情');
  }

  await setChatMessages(
    [{ message_id: 0, role: 'assistant', message: story }],
    { refresh: 'all' },
  );
  console.info('[迫降线] 已写入第 0 楼');
}
